import { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";
import { 
  ChevronDown, ChevronRight, LayoutGrid, BookOpen, 
  Settings, GraduationCap, CheckCircle2 
} from "lucide-react";
import axios from "../api/axios";

const Sidebar = () => {
  const location = useLocation();
  const [menuData, setMenuData] = useState([]);
  
  // Section Toggles
  const [adminOpen, setAdminOpen] = useState(true);
  const [examsListOpen, setExamsListOpen] = useState(true);
  
  // Dynamic Toggles (using IDs to track which item is open)
  const [openExams, setOpenExams] = useState({});
  const [openCategories, setOpenCategories] = useState({});

  useEffect(() => {
    const fetchSidebarData = async () => {
      try {
        // We use the public/menu-structure endpoint we created in server.js
        const res = await axios.get("/public/menu-structure");
        if (res.data.success) setMenuData(res.data.data);
      } catch (err) {
        console.error("Sidebar fetch failed", err);
      }
    };
    fetchSidebarData();
  }, []);

  const toggleExam = (id) => {
    setOpenExams(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const toggleCategory = (id) => {
    setOpenCategories(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const isActive = (path) => location.pathname === path;

  return (
    <div className="w-64 h-screen bg-gray-900 text-white flex flex-col border-r border-gray-800">
      {/* Header */}
      <div className="p-6 border-b border-gray-800 bg-gray-900/50">
        <h2 className="text-xl font-black uppercase tracking-tighter text-blue-500">MEDHASHALA</h2>
      </div>

      <div className="flex-1 p-4 overflow-y-auto space-y-6 custom-scrollbar">
        
        {/* --- DYNAMIC EXAMS LIST (ABOVE ADMIN) --- */}
        <div>
          <button
            onClick={() => setExamsListOpen(!examsListOpen)}
            className="flex justify-between items-center w-full py-2 mb-2 font-black uppercase text-[10px] tracking-widest text-gray-500 hover:text-white"
          >
            <span>Exams List</span>
            {examsListOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {examsListOpen && (
            <div className="space-y-1">
              {menuData.map((exam) => (
                <div key={exam._id} className="space-y-1">
                  {/* Exam Level */}
                  <button
                    onClick={() => toggleExam(exam._id)}
                    className="flex items-center justify-between w-full p-2 text-xs font-bold rounded-lg hover:bg-gray-800 transition-all text-gray-300"
                  >
                    <div className="flex items-center gap-2">
                      <GraduationCap size={16} className="text-blue-400" />
                      <span>{exam.examName}</span>
                    </div>
                    {openExams[exam._id] ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                  </button>

                  {/* Category Level */}
                  {openExams[exam._id] && (
                    <div className="ml-4 border-l border-gray-800 pl-2 space-y-1">
                      {exam.subCategories?.map((cat) => (
                        <div key={cat._id}>
                          <button
                            onClick={() => toggleCategory(cat._id)}
                            className="flex items-center justify-between w-full p-2 text-[11px] font-semibold text-gray-400 hover:text-white transition-all"
                          >
                            <span>{cat.catName}</span>
                            {openCategories[cat._id] ? <ChevronDown size={10} /> : <ChevronRight size={10} />}
                          </button>

                          {/* Features Level */}
                          {openCategories[cat._id] && (
                            <div className="ml-4 mt-1 space-y-1">
                              {cat.features?.map((feat) => (
                                <div key={feat} className="flex items-center gap-2 p-1.5 text-[10px] text-gray-500 hover:text-blue-400 cursor-pointer">
                                  <CheckCircle2 size={10} className="text-emerald-500" />
                                  <span>{feat}</span>
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>

        <hr className="border-gray-800" />

        {/* --- ADMIN CONTROLLER SECTION --- */}
        <div>
          <button
            onClick={() => setAdminOpen(!adminOpen)}
            className="flex justify-between items-center w-full py-2 mb-2 font-black uppercase text-[10px] tracking-widest text-gray-500 hover:text-white"
          >
            <span>Admin Controller</span>
            {adminOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {adminOpen && (
            <div className="space-y-1">
              <Link
                to="/dashboard/exam-master"
                className={`flex items-center gap-2 p-2 rounded-lg text-xs font-bold transition-all ${
                  isActive("/dashboard/exam-master") ? "bg-blue-600 text-white" : "text-gray-400 hover:bg-gray-800"
                }`}
              >
                <BookOpen size={14} /> Exam Master
              </Link>

              <Link
                to="/dashboard/category-master"
                className={`flex items-center gap-2 p-2 rounded-lg text-xs font-bold transition-all ${
                  isActive("/dashboard/category-master") ? "bg-emerald-600 text-white" : "text-gray-400 hover:bg-gray-800"
                }`}
              >
                <LayoutGrid size={14} /> Category Master
              </Link>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default Sidebar;
